const PROM = {
  cpu_busy:      `topk(10, 100 - avg by(instance)(rate(node_cpu_seconds_total{mode="idle"}[5m]))*100)`,
  load_per_core: `topk(10, node_load5 / count by(instance)(node_cpu_seconds_total{mode="idle"}))`,
  mem_avail_pct: `bottomk(10, node_memory_MemAvailable_bytes / node_memory_MemTotal_bytes * 100)`,
  disk_used_pct: `topk(10, 100 - node_filesystem_avail_bytes{fstype!~"tmpfs|overlay"} / node_filesystem_size_bytes * 100)`,
  inode_used:    `topk(10, 100 - node_filesystem_files_free / node_filesystem_files * 100)`,
  disk_io_sat:   `topk(10, rate(node_disk_io_time_seconds_total[5m]))`,
  net_err_drop:  `topk(10, rate(node_network_receive_errs_total[5m]) + rate(node_network_transmit_errs_total[5m]) + rate(node_network_receive_drop_total[5m]) + rate(node_network_transmit_drop_total[5m]))`,
  conntrack_pct: `topk(10, node_nf_conntrack_entries / node_nf_conntrack_entries_limit * 100)`,
};
return Object.entries(PROM).map(([check, query]) => ({ json: { role: "infra", check, query } }));

const role = $('Build Prom Queries').item.json.role;
const check = $('Build Prom Queries').item.json.check;
const query = $('Build Prom Queries').item.json.query;
const result = $json.data?.result ?? [];

return {
  json: {
    role,
    check,
    query,
    series_count: result.length,
    top: result.slice(0, 5).map(r => ({ instance: r.metric.instance ?? null, value: Number(r.value[1]) }))
  }
};

const PROM = {
  pods_abnormal:   `count by(namespace,phase)(kube_pod_status_phase{phase!~"Running|Succeeded"}==1)`,
  restarts_1h:     `topk(15, increase(kube_pod_container_status_restarts_total[1h]))`,
  deploy_unavail:  `kube_deployment_spec_replicas - kube_deployment_status_replicas_available > 0`,
  oomkilled:       `kube_pod_container_status_last_terminated_reason{reason="OOMKilled"}==1`,
  cfs_throttle_pct:`topk(15, rate(container_cpu_cfs_throttled_periods_total[5m]) / rate(container_cpu_cfs_periods_total[5m]) * 100)`,
  mem_vs_limit_pct:`topk(15, container_memory_working_set_bytes / on(namespace,pod,container) kube_pod_container_resource_limits{resource="memory"} * 100)`,
  apiserver_5xx:   `sum(rate(apiserver_request_total{code=~"5.."}[5m]))`,
  apiserver_p99:   `histogram_quantile(0.99, sum by(le,verb)(rate(apiserver_request_duration_seconds_bucket[5m])))`,
  pending_pods:    `scheduler_pending_pods`,
  // 님 스택 특화 — Spark/YuniKorn placeholder
  spark_pending:   `count(kube_pod_status_phase{phase="Pending", namespace=~"spark.*"}==1)`,
};
return Object.entries(PROM).map(([check, query]) => ({ json: { role: "k8s", check, query } }));

const queries   = $('Define Queries').all();   // 입력 순서 보존
const responses = $input.all();
const findings = [];

responses.forEach((res, i) => {
  const meta = queries[i].json;                 // check / role
  const result = res.json?.data?.result || [];
  result.forEach(s => {
    const m = s.metric || {};
    findings.push({
      check: meta.check,
      node: m.node || m.instance || null,       // ← 조인 키
      namespace: m.namespace || null,
      pod: m.pod || null,
      value: parseFloat(s.value?.[1]),
    });
  });
});
return [{ json: { role: queries[0].json.role, findings } }];

